from dataclasses import dataclass
from typing import Iterable


@dataclass
class Job:
    job_id: str
    status: str
    priority: int = 0


def get_pending_jobs(queue: list[Job]) -> Iterable[Job]:
    """Return pending jobs from the queue."""
    return (job for job in queue if job.status == "pending")


def count_by_status(queue: list[Job]) -> dict[str, int]:
    counts: dict[str, int] = {}
    for job in queue:
        counts[job.status] = counts.get(job.status, 0) + 1
    return counts
